import React, { useState, useEffect } from "react";

const FriendList = ({ goBack }) => {
  const [friends, setFriends] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [toast, setToast] = useState(null);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  // Lấy token từ localStorage
  const getToken = () => localStorage.getItem('token');

  // Fetch danh sách bạn bè
  const fetchFriends = async () => {
    try {
      const token = getToken();
      if (!token) {
        setError('Bạn cần đăng nhập');
        return;
      }

      const response = await fetch('http://localhost:3001/api/friends', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error('Không thể tải danh sách bạn bè');
      }

      const data = await response.json();
      setFriends(data.friends || []);
    } catch (err) {
      setError(err.message);
      console.error('Error fetching friends:', err);
    }
  };

  // Fetch danh sách người dùng để gợi ý kết bạn
  const fetchUsers = async () => {
    try {
      const token = getToken();
      if (!token) return;

      const response = await fetch('http://localhost:3001/api/users', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error('Không thể tải danh sách người dùng');
      }

      const data = await response.json();
      setUsers(data.users || []);
    } catch (err) {
      console.error('Error fetching users:', err);
    }
  };

  // Gửi lời mời kết bạn
  const sendFriendRequest = async (receiverId) => {
    try {
      const token = getToken();
      if (!token) {
        showToast('Bạn cần đăng nhập');
        return;
      }

      const response = await fetch('http://localhost:3001/api/friend-requests', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          receiver_id: receiverId,
          message: 'Xin chào, làm bạn với tôi nhé!'
        })
      });

      const data = await response.json();

      if (response.ok) {
        showToast('Đã gửi lời mời kết bạn');
        // Cập nhật trạng thái người dùng (đã gửi lời mời)
        setUsers(prev => prev.map(user =>
          user.id === receiverId ? { ...user, requestSent: true } : user
        ));
      } else {
        showToast(data.message || 'Không thể gửi lời mời');
      }
    } catch (err) {
      showToast('Lỗi khi gửi lời mời');
      console.error('Error sending friend request:', err);
    }
  };

  // Xóa bạn bè
  const removeFriend = async (friendId) => {
    // TODO: Implement remove friend API
    showToast('Chức năng xóa bạn bè chưa được implement');
  };

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      await Promise.all([fetchFriends(), fetchUsers()]);
      setLoading(false);
    };
    loadData();
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-xl">Đang tải...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <div className="text-red-500 text-xl mb-4">{error}</div>
        <button
          onClick={goBack}
          className="bg-blue-500 text-white px-4 py-2 rounded-lg"
        >
          Quay lại
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 p-6">
      {/* Toast */}
      {toast && (
        <div className="fixed top-5 right-5 bg-black text-white px-4 py-2 rounded-lg shadow-lg z-50">
          {toast}
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-3xl font-bold">Bạn bè</h1>
        <button
          onClick={goBack}
          className="bg-gray-500 text-white px-4 py-2 rounded-lg hover:bg-gray-600"
        >
          Quay lại
        </button>
      </div>

      <div className="flex gap-6">
        {/* Danh sách bạn bè */}
        <div className="flex-1 flex flex-col gap-4">
          <h2 className="text-2xl font-bold mb-3">Danh sách bạn bè ({friends.length})</h2>
          {friends.length === 0 ? (
            <div className="text-gray-500 text-center py-8">
              Bạn chưa có bạn bè nào. Hãy gửi lời mời kết bạn!
            </div>
          ) : (
            friends.map((friend) => (
              <div
                key={friend.id}
                className="flex items-center gap-4 bg-[#A2D3FF] p-4 rounded-lg shadow-sm"
              >
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
                  className="w-[90px] h-20 object-fill rounded-full"
                  alt="avatar"
                />
                <div className="flex-1">
                  <span className="text-black text-xl font-semibold">{friend.display_name}</span>
                  <div className="text-gray-600 text-sm">@{friend.username}</div>
                  <div className="text-gray-500 text-xs">
                    Bạn bè từ {new Date(friend.friend_since).toLocaleDateString('vi-VN')}
                  </div>
                </div>
                <button
                  onClick={() => removeFriend(friend.id)}
                  className="bg-red-500 text-white px-3 py-1 rounded-lg hover:bg-red-600"
                >
                  Xóa bạn
                </button>
              </div>
            ))
          )}
        </div>

        {/* Gợi ý kết bạn */}
        <div className="w-[400px] flex flex-col gap-3">
          <h2 className="text-2xl font-bold mb-3">Gợi ý kết bạn ({users.length})</h2>
          {users.slice(0, 10).map((user) => (
            <div
              key={user.id}
              className="flex items-center gap-4 bg-[#F0F8FF] p-4 rounded-lg shadow-sm"
            >
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
                className="w-[60px] h-16 object-fill rounded-full"
                alt="avatar"
              />
              <div className="flex-1">
                <span className="flex-1 text-black text-xl font-semibold">{user.display_name}</span>
                <div className="text-gray-600 text-sm">@{user.username}</div>
              </div>
              <button
                onClick={() => sendFriendRequest(user.id)}
                disabled={user.requestSent}
                className={`px-3 py-1 rounded-lg text-white ${
                  user.requestSent
                    ? 'bg-gray-400 cursor-not-allowed'
                    : 'bg-[#88BCF8] hover:bg-[#63A4F8]'
                }`}
              >
                {user.requestSent ? 'Đã gửi' : 'Thêm bạn'}
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default FriendList;
